import { useParams, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";

function OfferLetter() {
  const { applicationId } = useParams();
  const navigate = useNavigate();

  const [application, setApplication] = useState(null);

  /* ===== Offer Fields ===== */
  const [salary, setSalary] = useState("");
  const [joiningDate, setJoiningDate] = useState("");
  const [location, setLocation] = useState("");
  const [validTill, setValidTill] = useState("");
  const [notes, setNotes] = useState("");

  /* =========================
     LOAD APPLICATION
  ========================= */
  useEffect(() => {
    const apps =
      JSON.parse(localStorage.getItem("applications")) || [];

    const found = apps.find(
      a => String(a.id) === String(applicationId)
    );

    setApplication(found);
  }, [applicationId]);

  /* =========================
     SAVE OFFER LETTER
  ========================= */
  const handleSaveOffer = () => {
    if (!salary || !joiningDate || !location || !validTill) {
      alert("Please fill all required fields");
      return;
    }

    const offers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    const newOffer = {
      applicationId: application.id,
      empId: application.empId,
      name: application.employeeName,
      email: application.email,
      jobTitle: application.jobTitle,

      salary,
      joiningDate,
      location,
      validTill,
      notes,

      status: "OFFER_SENT",
      createdAt: new Date().toISOString()
    };

    offers.push(newOffer);
    localStorage.setItem("offerLetters", JSON.stringify(offers));

    alert("Offer Letter Saved Successfully");
    navigate("/dashboard/view-applicants");
  };

  if (!application) return <p>Loading...</p>;

  return (
    <div style={{ marginTop: "25px", maxWidth: "600px" }}>
      <h2>Generate Offer Letter</h2>

      <p><b>Name:</b> {application.employeeName}</p>
      <p><b>Email:</b> {application.email}</p>
      <p><b>Job Title:</b> {application.jobTitle}</p>

      <hr />

      <input
        type="number"
        placeholder="Annual Salary"
        value={salary}
        onChange={e => setSalary(e.target.value)}
      />

      <input
        type="date"
        value={joiningDate}
        onChange={e => setJoiningDate(e.target.value)}
      />

      <input
        type="text"
        placeholder="Location"
        value={location}
        onChange={e => setLocation(e.target.value)}
      />

      <input
        type="date"
        value={validTill}
        onChange={e => setValidTill(e.target.value)}
      />

      <textarea
        placeholder="Notes (optional)"
        value={notes}
        onChange={e => setNotes(e.target.value)}
      />

      <button
        style={{
          marginTop: "15px",
          background: "#2563eb",
          color: "white",
          padding: "10px 16px",
          borderRadius: "6px",
          border: "none"
        }}
        onClick={handleSaveOffer}
      >
        Save Offer Letter
      </button>
    </div>
  );
}

export default OfferLetter;
